• The API Routing Logic (app/api/chat/route.ts)
Here is how we handle incoming JSON payloads, enforce type safety using standard TypeScript interfaces, and safely return the generated stream or payload back to our UI components:

import { NextResponse } from 'next/server';
import { GoogleGenAI } from '@google/genai';
// Initialize the SDK with zero runtime overhead
const ai = new GoogleGenAI({ apiKey: process.env.GEMINI_API_KEY });
export async function POST(req: Request) {
try {
const { messages } = await req.json();
if (!messages || !Array.isArray(messages)) {
return NextResponse.json({ error: 'Invalid prompt payload structure' }, { status: 400 });
}
// Leveraging Gemini 2.5 Flash for sub-second responses
const response = await ai.models.generateContent({
model: 'gemini-2.5-flash',
contents: messages,
});
return NextResponse.json({ text: response.text });
} catch (error) {
console.error('Gemini Execution Error:', error);
return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 });
}
}

